var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"숨이 턱까지 차오를 만큼 지치지 않은 채로 잠들면, 종종 나쁜 꿈을 꾼다.","JPN":"息が苦しくなるほど体を酷使していない日は、時々悪い夢を見る。","ENG":"I often have nightmares if I don't exhaust myself to sleep.","TWN":"如果不是累到睡著的話老是會做惡夢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 식은땀에 절어 깊은 밤 눈을 뜨는 순간이면, 그 꿈이 현실로 이루어지지 않을지 불안을 곱씹는다.","JPN":"そして全身に冷汗をかいて深夜に目を覚まし、その夢が現実になるのではないかという不安に駆られる。","ENG":"Every time I wake up with a start, soaked in a cold sweat, I can't help but wonder if my nightmares will ever come true.","TWN":"全身冒著冷汗在夜裡睜開眼後，又會籠罩在擔心惡夢成真的不安裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……나는 대개 상대에게 창을 겨누는 편이었는데, 자네는 매번 내게 역으로 겨누는군.","JPN":"……たいていの場合、私は相手に槍を突きつけるほうだが、君が相手だと毎回逆に突きつけられるな。","ENG":"...Usually, it's I who holds the opponent at spearpoint. With you, I'm always on the other side of the spear.","TWN":"……通常我都是拿劍指著別人的，但每次跟你練習時都是反過來的呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"대련은 자네의 승리야. 정확하게 허점을 찔렸어.","JPN":"この手合わせは君の勝ちだ。見事に隙をつかれたよ。","ENG":"You won. Good job delivering a home-thrust.","TWN":"這次的練習是你獲勝，每個動作都命中紅心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"설령 레드 시프트들이라도, 자네만큼은 단장으로 인정할 걸세.","JPN":"レッドシフトも君のことを団長として認めるだろう。","ENG":"Even the Red Shifts will accept you as their captain, though begrudgingly.","TWN":"就算是紅移也會認同你這位團長吧！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"제 체면을 지켜 주실 요량으로 하는 말씀이라면 괜찮습니다. 버밍엄 교수님.","JPN":"私の面子を立てようとされているのなら大丈夫です、バーミンガム教授。","ENG":"If you're saying that to protect my pride, I'm okay, Professor Birmingham.","TWN":"伯明罕教授，你大可不必說這些話來安慰我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"지휘에서나 전투에서나, 아직 교수님을 넘어서기엔 갈 길이 멀군요.","JPN":"指揮も戦闘も、まだ教授にはまだまだ敵いません。","ENG":"I still have a long way to go before I outshine you as a leader, or as a fighter.","TWN":"無論是在指揮或是在戰鬥中，我都還差教授一大截呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"너무 서두르지 말게. 정진할 목표가 있다는 건 행복한 일이니까.","JPN":"急ぐ必要はない。目標のために精進できるのは幸せなことだ。","ENG":"No need to hurry. Having a goal is a good thing.","TWN":"別太心急，有明確的目標是一件很幸福的事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"기사단으로 돌아가기 전에 잠시 걷겠나? 새로 만든 산책로가 마음에 들면 좋겠군.","JPN":"騎士団に戻る前に、少し散歩でもしないか？　新しい遊歩道を気に入ってもらえるといいのだが。","ENG":"Before you go back to the Knights, how'd you like to take a stroll with me? I'd love to show you our new promenade.","TWN":"回去騎士團之前要一起散個步嗎？有一條新的散步路線，希望你會喜歡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"드나들 때마다 느끼지만, 보기보다 넓은 안뜰이군요.","JPN":"来るたびに思うのですが、意外と広い中庭ですね。","ENG":"Every time I come here, I can't help but admire this spacious courtyard you have.","TWN":"我每次來都覺得，這個地方比我看到的還寬敞呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"카운터 아카데미는 교직원들에 대한 대우에 상당히 공을 들이는 모양입니다.","JPN":"カウンターアカデミーは、教職員の待遇に相当力を入れているように感じます。","ENG":"The Counter Academy must be very good to its teaching staff.","TWN":"制裁者學院給教職員的待遇似乎非常大方呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이 공간은 동료 중 한 명이 조금 손본 것이라네.","JPN":"この空間は、仲間の1人が少し手入れしたものだ。","ENG":"One of my colleagues worked her magic upon it.","TWN":"這個空間是有位同事稍微整修過的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"순수한 선의만으로 만들지는 않았지만, 간혹 고민이 생기면 하염없이 걷기에 안성맞춤이지.","JPN":"ただの善意で作ったわけではないが、悩みがある時ただただ歩くにはもってこいの場所だよ。","ENG":"I doubt she created it purely out of the kindness of her heart, but still, I'm grateful to have a place to come to when I need to think.","TWN":"雖然不是出於善意而打造的空間，但偶爾遇到煩心的事時，很適合在這邊散心。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그 말씀은…….","JPN":"それは……","ENG":"You mean...","TWN":"教授的意思是……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"오늘은 평소보다 검이 무겁더군.","JPN":"今日は普段より剣に迷いがあった。","ENG":"Your sword was more sluggish than usual.","TWN":"你今天的動作比較沒那麼俐落喔。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고민거리가 있다면 얘기해 보게.","JPN":"悩みがあるなら言いたまえ。","ENG":"You can talk to me if you have a problem.","TWN":"有什麼煩惱的話可以說出來。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"상담도 전술학의 일부란 사실은 처음 알았습니다.","JPN":"相談も戦術学の一部だとは知りませんでした。","ENG":"I didn't know consultation was part of strategy class.","TWN":"原來心理諮商也是戰術學的一部份嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"학생들의 고충을 상담해 주는 건 교사가 당연히 해야 할 일이라네.","JPN":"学生の悩みを聞くのは教師として当然のことだ。","ENG":"It's only natural that I want to help my students with their problems as their mentor.","TWN":"聆聽學生的煩惱是老師應該做的吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 조디악 나이츠의 단장이라면, 없는 시간을 쪼개서라도 이야기를 나누고 싶군.","JPN":"しかもそれがゾディアックナイツの団長ともなると、暇を作ってでも話を聞いてみたいと思うものさ。","ENG":"Also, you're the captain of the Zodiac Knights. I can always make time for you.","TWN":"更何況你還是十二宮騎士團的團長，就算沒時間我也要擠出時間來聽你說。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그건…… 교수님의 집안이 조디악 나이츠를 오랜 세월 조력해 왔기 때문입니까?","JPN":"それは……教授の家が、長い間ゾディアックナイツに協力してきたからですか？","ENG":"Is it because... your family supported the Zodiac Knights for a long time?","TWN":"是因為……教授的家族一直以來都在協助十二宮騎士團嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"기사단의 창립자인 <color=#ffd34c>별의 인도자</color>와 우리 가문의 조상은 막역한 친우였다지.","JPN":"騎士団の創立者である<color=#ffd34c>星の導き手</color>と、我が家の先祖は親友だったらしい。","ENG":"Your founder, the <color=#ffd34c>Star Guide</color> was good friends with my ancestors.","TWN":"騎士團的創辦人 <color=#ffd34c>星之引導者</color>，和我們家族的祖先是莫逆之交的嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"친우가 서로의 고민을 덜어 주는 건 흔한 일 아닌가.","JPN":"親友とは悩みも分け合うものだろう。","ENG":"Friends listen to each other's problems, don't they?","TWN":"好朋友之間互吐心事，不是再正常不過的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"악몽 때문입니다.","JPN":"悪夢のせいです。","ENG":"My nightmares.","TWN":"是因為做惡夢的關係。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"악몽이라…….","JPN":"悪夢か……","ENG":"Nightmares...","TWN":"惡夢……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자세히 얘기해 줄 수 있겠나?","JPN":"詳しく聞かせてもらえるかな？","ENG":"Could you elaborate on that?","TWN":"你願意說給我聽嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이전에는 전투 중에 버고 소드가 풍선으로 바뀌거나 동굴 속 살인 토끼와 사투를 벌이는 정도였지만…….","JPN":"以前は、戦闘中にヴァルゴソードが風船になりすましたり、洞窟で殺人うさぎと死闘を繰り広げたりするくらいでしたが……","ENG":"Before, I only dreamed about the Virgo Sword turning into balloons in the middle of a fight or dueling with a killer rabbit in a den…","TWN":"在夢裡，不是布爾加夫之劍突然變成氣球，就是在洞穴裡和殺人兔廝殺……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……그건 그것대로 심각했군.","JPN":"……それはそれで、大変な夢だったな。","ENG":"...Even they sound serious.","TWN":"……聽起來確實很可怕的感覺。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버고 소드를 뽑은 이래, 같은 악몽을 계속해서 꾸게 되었습니다.","JPN":"ヴァルゴソードを抜いてから、ずっと同じ悪夢を繰り返して見ているのです。","ENG":"Since I drew the Virgo Sword, I've been dreaming the same nightmare over and over again.","TWN":"自從我拔出布爾加夫之劍後，就一直做著相同的惡夢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"같은 악몽이라고?","JPN":"同じ悪夢を？","ENG":"What sort of nightmare?","TWN":"相同的惡夢嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"네. 아주 먼 옛날의, 아름다운 도시가 불타오르는 광경이었죠.","JPN":"はい。遠い昔の、美しい都市が燃え上がる光景を。","ENG":"I see a very ancient and beautiful city, on fire.","TWN":"對，場景是很久以前在一個燃燒的美麗城市。"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그곳에서 저는 항상 부러진 검을 든 채로……. 우두커니 서 있어야 했습니다.","JPN":"そこで私はいつも、折れた剣を手にしたまま……ただ呆然と立っていました。","ENG":"I'm standing in the middle of this city... holding a broken sword.","TWN":"我在那個地方，手裡拿著一把斷掉的劍……茫然地站著。"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"꿈 속의 동료들이 사악하고 거대한 무언가와 맞서는 모습을 지켜만 보면서.","JPN":"夢の中の仲間たちが邪悪で巨大な何かと戦う姿を、ただ見ていることしかできずに。","ENG":"I'm just watching others fight something evil and humongous.","TWN":"在夢裡，我看著夥伴們在對抗邪惡又巨大的東西，"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"처음에는 단장으로서의 부담감을 꿈에서 겪었다고 여겼지만, 지금은 아니라고 생각합니다.","JPN":"最初は、団長としてのプレッシャーが夢に現れたのだと思いましたが、今は違います。","ENG":"At first, I brushed it off as a figment of my sense of responsibility as captain. Now, I don't think it is.","TWN":"那時我在夢裡感受到身為團長的重任，但現在卻不那麼認為。"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 그 무력감은…….","JPN":"しかしその無力感……","ENG":"And the sense of hopelessness...","TWN":"那個無力感……"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사의 소임을 다할 수 없다는 무력감은, 몇 번을 겪어도 익숙해지기 어렵더군요.","JPN":"騎士の務めを全うできないその無力感は、何度味わっても慣れないものです。","ENG":"I will never get used to the sense of hopelessness that comes from my inability to fulfill my knightly duty.","TWN":"那個無法善盡騎士之責的無力感，無論經歷過幾次我都無法適應。"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그건 어쩌면 버고 소드에 깃든 기억일지도 모르겠군.","JPN":"もしかすると、それはヴァルゴソードに宿る記憶かもしれない。","ENG":"Maybe you're seeing some memories held within the Virgo Sword.","TWN":"那個會不會是烙印在布爾加夫之劍裡的記憶呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"버고 소드에……?","JPN":"ヴァルゴソードの……？","ENG":"Within the Virgo Sword?","TWN":"布爾加夫之劍裡的嗎……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"별의 인도자에 대한 전승은 기사단에 수없이 많지만, 정작 그가 어디서 왔는지 설명하는 이야기는 없다.","JPN":"騎士団に伝わる、星の導き手の伝承は数多く存在する。しかし彼がどこから来たかについて説明する話はないんだ。","ENG":"Many stories about the Star Guide are told among the Knights, but none of them explains where he came from.","TWN":"雖然星之引導者的繼承已經在騎士團裡進行過無數次，但他到底從何而來卻沒有人知道。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그렇다면 만약에, 인도자가 다른 세계에서 왔다면.","JPN":"もし、導く者が別の世界から来たのだとすれば、","ENG":"What if the Guide came from a different world?","TWN":"萬一引導者是從別的世界來的呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 자신의 세계가, 멸망의 위기에 내몰려 있었다면.","JPN":"そして自分の世界が滅亡の危機に晒されていたとすれば、","ENG":"And it was on the verge of destruction?","TWN":"如果他的世界正面臨滅亡的危機呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"고향에 비해 터무니없이 낙후되었던 과거의 이 세계를 보고 결단을 내렸을지도 모르지.","JPN":"故郷に比べると遥かに劣っていた、過去のこの世界を見て決心したのかもしれない。","ENG":"And what if our world was way behind his own? Maybe he didn't want it to end up like his home.","TWN":"很可能他看到過去的世界如此落後，於是決定，"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"언젠가 이곳에도 닥칠 멸망에 대비할 수 있는 희망을…….","JPN":"いつかこの世界にも迫るであろう滅亡に備えることができるよう、希望を……","ENG":"Maybe that's why he planted hope for the future…","TWN":"為這個總有一天會面臨到滅亡的地方，留下希望……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어두운 밤에 길 잃고 헤매는 이들을 인도해 줄 별빛을 남기기로.","JPN":"闇夜で道に迷っている者たちを導く星の光を残そうと。","ENG":"He left the starlight to guide the lost back to the right track.","TWN":"為那些在暗夜中迷路的人，留下指引的星光。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"너무 진지하게 이야기했군.","JPN":"少し熱くなりすぎたか。","ENG":"That was too serious, wasn't it?","TWN":"好像有點太認真了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"방금 한 이야기는 어디까지나 가정에 불과하다네.","JPN":"だが、今の話はあくまで仮定に過ぎない。","ENG":"But it's just my theory.","TWN":"我剛說的那番話都只是猜測而已。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"열두 무구와 같이 유서 깊은 고유무장에 대한 연구는 학계에서도 진전이 없는 실정일세.","JPN":"12武具のように、由緒ある固有武装に関する研究は学会でもなかなか難航している。","ENG":"Not much study has been done on historic Unique Gear like the Twelve Armaments, even in the academic world.","TWN":"畢竟有關十二武具，和歷史久遠的專屬裝備之研究，學界目前也沒有任何進展。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면…….","JPN":"それなら……","ENG":"Then...","TWN":"這麼說來……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"제 오빠도, 같은 꿈을 꿨겠군요.","JPN":"兄も、同じ夢を見たのでしょうね。","ENG":"My brother must have had the same dream.","TWN":"那我哥哥，應該也有做相同的夢吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전임 단장이 악몽 때문에 버고 소드를 버리고 종적을 감췄다고 생각하진 말게.","JPN":"前団長が悪夢のせいでヴァルゴソードを捨て、姿を消したのだとは思わないでくれ。","ENG":"Don't think your former captain abandoned the Virgo Sword and disappeared because of his nightmares.","TWN":"不要以為上一任團長是因為惡夢，才丟掉布爾加夫之劍銷聲匿跡的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"역대 단장 중에 어느 누구도 자네와 같은 현상을 겪진 않았어.","JPN":"歴代の団長の中で、君と同じ経験をした人は誰もいない。","ENG":"No captains in history experienced the same symptoms as you.","TWN":"在歷任團長當中，沒有一個人有和你相同的經歷。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"적어도 <color=#ffd34c>내</color>가 아는 한에선 말일세.","JPN":"少なくとも<color=#ffd34c>私</color>の知る限りでは。","ENG":"Or at least as far as <color=#ffd34c>I</color> know.","TWN":"至少<color=#ffd34c>就我知道的</color>是這樣。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 납득하기 어렵습니다.","JPN":"ですが、納得いきません。","ENG":"But I don't understand.","TWN":"但我無法接受。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"역대 단장들은 전부 별의 궤적을 그리기에 부끄럽지 않은 인물들이었습니다.","JPN":"歴代の団長は皆、星の軌跡を描くに相応しい人々でした。","ENG":"Each and every captain in history was great, enough to decorate the heavens with their own constellation.","TWN":"歷任團長都是敢於畫出星之軌跡的人物。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"저 한 사람에게 이 사실을 알려야 할 이유는 헤아릴 수가 없군요.","JPN":"私だけにこの事実を知らせる意味が……私にはわかりません。","ENG":"I don't understand why I'm the only one being informed of this.","TWN":"我想不透必須把這件事告訴我一個人的理由是什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"자네에게서 다른 단장들에게 없었던 가능성을 찾았을지도 모르지.","JPN":"君から、他の団長にはなかった可能性を見出したのかもしれない。","ENG":"Perhaps you have something that the other captains didn't have.","TWN":"或許是在你身上找到其他團長沒有的可能性。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"혹은, 그가 목격했던 멸망의 순간이 가까워졌거나.","JPN":"あるいは、彼が目にした滅亡の瞬間が近づいてきたとか。","ENG":"Or the end that the Guide saw is near.","TWN":"又或者，他親眼目睹的滅亡瞬間逼近中。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇군요. 이야기를 들으니 확실해졌습니다.","JPN":"そうですか。その話を聞いて、確信が持てました。","ENG":"I see. This conversation with you confirms it.","TWN":"原來如此，聽完教授的話，我明白了一件事。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"별의 인도자 역시, 도움이 필요했던 분이셨군요.","JPN":"星の導き手も、助けが必要だったのですね。","ENG":"The Star Guide needed help, just like everyone else.","TWN":"那就是，星之引導者也是需要幫助的人！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"음……?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"위험에 처한 사람들을 돕는다. 조디악 나이츠의 제 1 원칙입니다.","JPN":"いついかなる時も危険にさらされた人々を救うのが、ゾディアックナイツの最大の使命です。","ENG":"Help people in distress. The very first rule of the Zodiac Knights.","TWN":"幫助處於危難的人，是十二宮騎士團的第一大原則。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"악인이 아니라면, 그가 누구든 예외는 없습니다.","JPN":"相手が悪人でない限り、例外はありません。","ENG":"No exceptions, unless they're villains.","TWN":"沒有一個人是例外的，除非他是作惡多端的人。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 제가 단장으로 있는 한 없게 할 겁니다.","JPN":"私が団長である以上、例外など許しません。","ENG":"Or at least there will be no exceptions as long as I'm captain.","TWN":"不，只要我是團長，就沒有例外。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"설령 제 검이 꺾이는 때가 오더라도.","JPN":"たとえ私の剣が折れるとしても。","ENG":"Even if my sword breaks.","TWN":"就算我的劍斷掉也是如此。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"악몽이 자네를 계속 괴롭힐 수도 있어. 그래도 괜찮겠나.","JPN":"今後も悪夢に苦しめられるかもしれない。それでも構わないのか？","ENG":"That nightmare will continue to torment you. Are you sure?","TWN":"但惡夢可能會持續折磨你，這樣也沒關係嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"좌절 속에서 도움을 청하는 목소리라면, 그건 악몽이 아닙니다.","JPN":"挫折の中で助けを求めているのならば、それは悪夢ではありません。","ENG":"It's not a nightmare if it's someone's call for help.","TWN":"若那是在挫折中求助的聲音，那就不是惡夢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사로서 기꺼이 답해야 할 부름이죠.","JPN":"騎士としてその呼び声に応じるべきなのです。","ENG":"And I'll gladly answer that call.","TWN":"身為騎士，就應該欣然回應。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 다음 대련에선 저에게 의도적으로 허점을 보여 주시지 않으셔도 됩니다.","JPN":"ですから、次の手合わせではわざと私に勝たせようとしなくても大丈夫です。","ENG":"So, please don't give me openings on purpose the next time we spar.","TWN":"所以之後練習時，教授可以不用再故意對我露出破綻。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그 무력감을 현실에서 느끼지 않으려면, 저 역시 스스로를 더욱 연마해야 하니까요.","JPN":"あの無力感が現実にならないよう、もっと己を磨き上げなければならないので。","ENG":"I must hone my skills to make sure I won't feel a sense of hopelessness in real life.","TWN":"因為我如果不想在現實中感受到那樣的無力感，就必須更多地磨練自己。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"대담한 선언이군.","JPN":"それは大胆なことを言うもんだな。","ENG":"That's a bold declaration.","TWN":"非常勇敢的宣告。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하긴, 그 정도로 대담하지 않았다면 평기사들 앞에서 오빠가 했던 맹세를 읊지도 않았겠지.","JPN":"まあ、それぐらいの大胆さがなければ、そもそも平騎士たちの前で兄の誓いを述べるなんてことはできないよな。","ENG":"But then again, if you weren't so bold, you wouldn't have dared reiterate your brother's pledges before the knight bachelors.","TWN":"也是，如果你不夠勇敢的話，又怎麼敢在平民騎士面前宣示哥哥的誓詞呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크흠. 주교님께서 벌써 말씀하셨군요.","JPN":"コホン……主教に聞きましたか。","ENG":"Ahem. So, His Excellency spoke to you already.","TWN":"咳咳，原來主教早就跟你說啦？！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"시기가 시기이니만큼, 걱정할 만해.","JPN":"確かにこんなご時世だ。心配するのもわかる。","ENG":"He was worried. Rightfully so.","TWN":"真是令人擔心呢。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그림자 하나 격퇴하고 안도하던 옛날과는 시대가 달라졌으니 말이야.","JPN":"シャドウを1体撃退したら安心できた昔とは状況が違うからな。","ENG":"Time has changed. Just defeating a Shadow isn't enough to ensure peace.","TWN":"畢竟現在和以前不同，不是打敗一個暗影，就能夠安居樂業的時代。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"산책은 여기서 마치지. 기분을 풀어 줄 생각이었는데 무거운 얘기만 했군.","JPN":"散歩はこの辺で切り上げるとしよう。気分転換のつもりが重い話ばかりしてしまってすまない。","ENG":"Let's go back. I'm sorry I brought up such a heavy topic instead of lifting your spirit like I wanted to.","TWN":"那我們就散步到這裡吧。本來是想替你開解的，結果盡是些沉重的話題。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아닙니다. 가벼운 이야기는 성격에 안 맞으니까요.","JPN":"いえ、そもそも軽い雑談をするような性格でもありませんし。","ENG":"No worries. I'm not interested in gossiping, anyway.","TWN":"沒關係，輕鬆的話題不符合我的個性。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"돌아가기 전에, 한 번 더 대련을 부탁드려도 되겠습니까?","JPN":"帰る前に、もう一度手合わせをお願いしてもいいでしょうか？","ENG":"Before I leave, mind if I ask you for another match?","TWN":"我回去前，可以再和我練習一場嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……그러지. 자네만 괜찮다면.","JPN":"……いいだろう。君さえよければ。","ENG":"…Sure, it'd be my pleasure.","TWN":"……沒問題，只要你願意。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};